#!/usr/bin/env bash
# Submit the gemma4-12b-it admission gate with a freshly built paris-probe-rknot.
#
# This stages only the Rust source slice required by distributed-inference:
# bitwise plus the gnosis-frf/helix/http/engine-core/rtl-bridge dependencies and
# distributed-inference. It avoids the stale R2-hosted probe binary used by the
# no-source admission path.
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
DI_ROOT="$(cd "${SCRIPT_DIR}/.." && pwd)"
GNOSIS_ROOT="$(cd "${DI_ROOT}/.." && pwd)"
OPEN_SOURCE="$(cd "${GNOSIS_ROOT}/.." && pwd)"
BITWISE="${OPEN_SOURCE}/bitwise"
GNOSIS_FRF="${GNOSIS_ROOT}/gnosis-frf"
GNOSIS_HELIX="${GNOSIS_ROOT}/gnosis-helix"
GNOSIS_HTTP="${GNOSIS_ROOT}/gnosis-http"
GNOSIS_ENGINE_CORE="${GNOSIS_ROOT}/gnosis-engine-core"
RTL_BRIDGE="${GNOSIS_ROOT}/rtl-bridge"
CONFIG="${GNOSIS_ROOT}/cloudbuild-gemma4-12b-it-admission-source.yaml"

for path in "${BITWISE}" "${GNOSIS_FRF}" "${GNOSIS_HELIX}" "${GNOSIS_HTTP}" "${GNOSIS_ENGINE_CORE}" "${RTL_BRIDGE}" "${DI_ROOT}"; do
  if [[ ! -d "${path}" ]]; then
    echo "submit-gemma4-12b-admission-cloud.sh: missing directory: ${path}" >&2
    exit 1
  fi
done
if [[ ! -f "${CONFIG}" ]]; then
  echo "submit-gemma4-12b-admission-cloud.sh: missing config: ${CONFIG}" >&2
  exit 1
fi
if ! command -v rsync >/dev/null 2>&1; then
  echo "submit-gemma4-12b-admission-cloud.sh: rsync is required" >&2
  exit 1
fi

TMP="$(mktemp -d)"
cleanup() {
  rm -rf "${TMP}"
}
trap cleanup EXIT

mkdir -p "${TMP}/gnosis"
rsync -a --exclude=target --exclude=.git --exclude=datasets "${BITWISE}/" "${TMP}/bitwise/"
rsync -a --exclude=target --exclude=.git "${GNOSIS_FRF}/" "${TMP}/gnosis/gnosis-frf/"
rsync -a --exclude=target --exclude=.git "${GNOSIS_HELIX}/" "${TMP}/gnosis/gnosis-helix/"
rsync -a --exclude=target --exclude=.git "${GNOSIS_HTTP}/" "${TMP}/gnosis/gnosis-http/"
rsync -a --exclude=target --exclude=.git "${GNOSIS_ENGINE_CORE}/" "${TMP}/gnosis/gnosis-engine-core/"
rsync -a --exclude=target --exclude=.git "${RTL_BRIDGE}/" "${TMP}/gnosis/rtl-bridge/"
rsync -a --exclude=target --exclude=.git "${DI_ROOT}/" "${TMP}/gnosis/distributed-inference/"
cp "${CONFIG}" "${TMP}/gnosis/cloudbuild-gemma4-12b-it-admission-source.yaml"

cd "${TMP}"
CMD=(
  gcloud builds submit
  --async
  --config=gnosis/cloudbuild-gemma4-12b-it-admission-source.yaml
  .
)
echo "Running: ${CMD[*]}"
"${CMD[@]}"
